targets.expr:
(
    last_over_time(
      peerobserver_conn_inbound_current{host="$HOST"}
      [2m:1s]
    )
    < bool last_over_time
    (
      (
        clamp_min(min without(prediction_type)
        (
          label_replace(
            # margin_lower_band
            avg_over_time(peerobserver_conn_inbound_current{host="$HOST"}[$SHORT_LOOKBACK:1m]) / $MARGIN_MULTIPLIER,
            "prediction_type", "margin", "", ""
          )
          or
          # lower_band_st
          label_replace(
            avg_over_time(peerobserver_conn_inbound_current{host="$HOST"}[$SHORT_LOOKBACK:1m])
            # anomaly:adaptive:stddev_st
            - avg_over_time
            (
              (
                # anomaly:adaptive:stddev_1h:filtered
                stddev_over_time
                (
                  peerobserver_conn_inbound_current{host="$HOST"}
                  [$SHORT_LOOKBACK:1m]
                )
                > avg_over_time
                (
                  peerobserver_conn_inbound_current{host="$HOST"}
                  [$SHORT_LOOKBACK:1m]
                )
                * $THRESHOLD_BY_COVAR
              )
              [$LONG_LOOKBACK:1m]
            )
            * $STDDEV_MULTIPLIER,
            "prediction_type", "short_term", "", ""
          )
        ), 0)
      )
      [2m:1s]
    )
)
